    idx = 0
    t = int(input_data[idx]); idx += 1
    for _ in range(t):
        n = int(input_data[idx]); idx += 1
        a = list(map(int, input_data[idx:idx+n])); idx += n

        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i+1] = prefix[i] + a[i]

        def range_sum(l, r):  # [l, r)
            return prefix[r] - prefix[l]

        def check(k):
            if k * (k + 1) // 2 > n:
                return False
            if k == 0:
                return True

            NEG_INF = -1
            # Segment tree for range max query
            size = 1
            while size < n + 1:
                size <<= 1
            tree = [-1] * (2 * size)

            def update(pos, val):
                pos += size
                tree[pos] = max(tree[pos], val)
                pos >>= 1
                while pos >= 1:
                    tree[pos] = max(tree[2*pos], tree[2*pos+1])
                    pos >>= 1

            def query_max(l, r):  # [l, r)
                res = -1
                l += size; r += size
                while l < r:
                    if l & 1:
                        res = max(res, tree[l]); l += 1
                    if r & 1:
                        r -= 1; res = max(res, tree[r])
                    l >>= 1; r >>= 1
                return res

            # Process from segment k (length 1) back to segment 1 (length k)
            # valid[j] = sum if position j is valid for current segment layer, else -1

            # Layer for length=1 (segment k)
            valid = {}
            for j in range(n - 1 + 1):
                s = range_sum(j, j + 1)
                valid[j] = s

            for length in range(2, k + 1):
                # Build seg tree from previous valid layer
                tree = [-1] * (2 * size)
                for j, s in valid.items():
                    update(j, s)

                new_valid = {}
                for j in range(n - length + 1):
                    s = range_sum(j, j + length)
                    nxt_start = j + length
                    mx = query_max(nxt_start, n)
                    if mx > s:
                        new_valid[j] = s
                valid = new_valid

            return len(valid) > 0

        hi = 0
        while (hi + 1) * (hi + 2) // 2 <= n:
            hi += 1

        ans = 0
        lo, hi2 = 0, hi
        while lo <= hi2:
            mid = (lo + hi2) // 2
            if check(mid):
                ans = mid
                lo = mid + 1
            else:
                hi2 = mid - 1

        print(ans)

